import sys
from collections import defaultdict

def solve(n: int, edges: list[list[int]], label: str) -> int:
    graph = defaultdict(list)
    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)

    max_len = 1

    def is_palindrome(s: str) -> bool:
        return s == s[::-1]

    for mask in range(1, 1 << n):
        path = []
        for i in range(n):
            if mask & (1 << i):
                path.append(i)
        # Check if the path is connected and forms a valid path (like a tree path)
        # To check connectivity, we can use BFS or DFS
        if len(path) == 1:
            if is_palindrome(label[path[0]]):
                max_len = max(max_len, 1)
            continue

        # Check if the nodes form a connected component
        visited = set()
        stack = [path[0]]
        visited.add(path[0])
        while stack:
            node = stack.pop()
            for neighbor in graph[node]:
                if (mask & (1 << neighbor)) and neighbor not in visited:
                    visited.add(neighbor)
                    stack.append(neighbor)
        if len(visited) != len(path):
            continue

        # Now check if the path is a valid path (i.e., no branches, just a simple path)
        # To do this, count the number of nodes with degree > 2 in the subgraph
        degree = defaultdict(int)
        for node in path:
            for neighbor in graph[node]:
                if mask & (1 << neighbor):
                    degree[node] += 1
        cnt = 0
        for node in path:
            if degree[node] > 2:
                cnt += 1
        if cnt > 0:
            continue

        # Now check if the string is a palindrome
        s = ''.join([label[i] for i in path])
        if is_palindrome(s):
            max_len = max(max_len, len(s))

    return max_len
